import{_ as r}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as n,c as d,a as e,b as a,d as i,e as s}from"./app-aa44b474.js";const c={},h=s('<h1 id="输入法" tabindex="-1"><a class="header-anchor" href="#输入法" aria-hidden="true">#</a> 输入法</h1><div class="subtitle">——windows 端的输入法都是一坨垃圾。</div><p>我的手机端输入法使用 Gboard，除了语音输入比较烂以外没啥缺点。windows 端我从初中就开始用 <em>手心输入法</em>，体验也还不错。但我刚需的语音输入在 <em>手心输入法</em> 中并不自带，使用微软的语音输入识别率又极为感人，因此尝试了一些其他输入法，并把我对每个输入法的评价写于此文。</p><h2 id="手心输入法" tabindex="-1"><a class="header-anchor" href="#手心输入法" aria-hidden="true">#</a> 手心输入法</h2><p>这是陪伴我最久的一个输入法，轻量级，无广告，双拼方案多。</p><h2 id="微软输入法" tabindex="-1"><a class="header-anchor" href="#微软输入法" aria-hidden="true">#</a> 微软输入法</h2><p>windows 自带的输入法，继承了微软一贯以来的毛病：<strong>强迫你接受微软的设计理念</strong>。它提供的自定义选项少得可怜，我无法获得我需要的体验。并且其未内置小鹤双拼方案，我需要自行修改注册表：</p><ol><li>打开 regedit，在 <code>计算机\\HKEY_CURRENT_USER\\Software\\Microsoft\\InputMethod\\Settings\\CHS</code> 路径下添加字符串值，名称为 <code>UserDefinedDoublePinyinScheme0</code>，值为 <code>小鹤双拼 *2*^*iuvdjhcwfg^xmlnpbksqszxkrltvyovt</code>，注意空格。</li><li>在双拼方案中选择 <em>小鹤双拼</em>。</li></ol><p>不过微软输入法也有优点：其是我用过的输入法中<strong>唯一</strong>支持 <em>暗黑模式</em> 的。这项对我来说也是刚需，只是平常都在忍受而已。</p><h2 id="讯飞输入法" tabindex="-1"><a class="header-anchor" href="#讯飞输入法" aria-hidden="true">#</a> 讯飞输入法</h2><p>试用讯飞输入法主要还是看重了它的语音输入能力，实际体验也确实不错。但最终我还是放弃了它，只有这一个原因：<strong>切换输入法时会卡</strong>。</p><p>我使用 <code>Ctrl + Shift</code> 切换输入法，而在切换到讯飞输入法时需要多按住 <code>Ctrl</code> 约 0.3s，这是我不能接受的。虽然 windows 官方推荐使用 <code>win + space</code> 切换输入法并且此方式没有问题，但我还是选择继续使用手心输入法。</p><h2 id="其他" tabindex="-1"><a class="header-anchor" href="#其他" aria-hidden="true">#</a> 其他</h2>',13),l={id:"capswriter",tabindex:"-1"},p=e("a",{class:"header-anchor",href:"#capswriter","aria-hidden":"true"},"#",-1),_={href:"https://github.com/HaujetZhao/CapsWriter",target:"_blank",rel:"noopener noreferrer"},m=e("p",null,[a("这是一款语音输入工具。但是使用它需要购买阿里云的 API，而现在语音 API 的价格普遍都挺可观，逼迫我放弃了这个想法。"),e("s",null,"你们移动端都是给免费随便用的喂！")],-1);function f(u,x){const t=o("ExternalLinkIcon");return n(),d("div",null,[h,e("h3",l,[p,a(),e("a",_,[a("CapsWriter"),i(t)])]),m])}const g=r(c,[["render",f],["__file","input_method.html.vue"]]);export{g as default};
